   102	    let after_pub = trimmed_line.strip_prefix("pub")?;
   103	    if after_pub.chars().next().is_some_and(char::is_whitespace) {
   104	        let after_visibility = after_pub.trim_start();
   105	        return after_visibility
   106	            .starts_with("use ")
   107	            .then_some(after_visibility);
   108	    }
