   118	fn strip_comments_and_strings(source: &str) -> String {
   119	    let chars = source.chars().collect::<Vec<_>>();
   120	    let mut stripped = String::with_capacity(source.len());
   121	    let mut index = 0;
   122	
   123	    while index < chars.len() {
   124	        if starts_with(&chars, index, &['/', '/']) {
   125	            push_replacement(&mut stripped, chars[index]);
   126	            push_replacement(&mut stripped, chars[index + 1]);
   127	            index += 2;
   128	            while index < chars.len() && chars[index] != '\n' {
   129	                push_replacement(&mut stripped, chars[index]);
   130	                index += 1;
   131	            }
   132	            continue;
   133	        }
   134	
   135	        if starts_with(&chars, index, &['/', '*']) {
   136	            push_replacement(&mut stripped, chars[index]);
   137	            push_replacement(&mut stripped, chars[index + 1]);
   138	            index += 2;
   139	            while index < chars.len() {
   140	                let current = chars[index];
   141	                let is_block_end = starts_with(&chars, index, &['*', '/']);
   142	                push_replacement(&mut stripped, current);
   143	                index += 1;
   144	                if is_block_end {
   145	                    push_replacement(&mut stripped, chars[index]);
   146	                    index += 1;
   147	                    break;
   148	                }
   149	            }
   150	            continue;
   151	        }
   152	
   153	        if let Some(raw_string_end) = raw_string_end(&chars, index) {
   154	            while index < raw_string_end {
   155	                push_replacement(&mut stripped, chars[index]);
   156	                index += 1;
   157	            }
   158	            continue;
   159	        }
   160	
   161	        if let Some(char_literal_end) = char_literal_end(&chars, index) {
   162	            while index < char_literal_end {
   163	                push_replacement(&mut stripped, chars[index]);
   164	                index += 1;
   165	            }
   166	            continue;
   167	        }
   168	
   169	        if chars[index] == '"' {
   170	            push_replacement(&mut stripped, chars[index]);
   171	            index += 1;
   172	            let mut escaped = false;
   173	            while index < chars.len() {
   174	                let current = chars[index];
   175	                push_replacement(&mut stripped, current);
   176	                index += 1;
   177	                if current == '"' && !escaped {
   178	                    break;
   179	                }
   180	                escaped = current == '\\' && !escaped;
   181	                if current != '\\' {
   182	                    escaped = false;
   183	                }
   184	            }
   185	            continue;
   186	        }
   187	
   188	        stripped.push(chars[index]);
   189	        index += 1;
   190	    }
   191	
   192	    stripped
   193	}
