   209	fn raw_string_end(chars: &[char], start: usize) -> Option<usize> {
   210	    let mut cursor = start;
   211	    if chars.get(cursor) == Some(&'b') {
   212	        cursor += 1;
   213	    }
   214	    if chars.get(cursor) != Some(&'r') {
   215	        return None;
   216	    }
   217	    cursor += 1;
   218	
   219	    let mut hashes = 0;
   220	    while chars.get(cursor) == Some(&'#') {
   221	        hashes += 1;
   222	        cursor += 1;
   223	    }
   224	    if chars.get(cursor) != Some(&'"') {
   225	        return None;
   226	    }
   227	    cursor += 1;
   228	
   229	    while cursor < chars.len() {
   230	        if chars[cursor] == '"' {
   231	            let hash_end = cursor + 1 + hashes;
   232	            if hash_end <= chars.len()
   233	                && chars[cursor + 1..hash_end]
   234	                    .iter()
   235	                    .all(|character| *character == '#')
   236	            {
   237	                return Some(hash_end);
   238	            }
   239	        }
   240	        cursor += 1;
   241	    }
   242	
   243	    Some(chars.len())
   244	}
   245	
   246	fn char_literal_end(chars: &[char], start: usize) -> Option<usize> {
   247	    if chars.get(start) != Some(&'\'') {
   248	        return None;
   249	    }
   250	
   251	    let character = *chars.get(start + 1)?;
   252	    if character == '\n' {
   253	        return None;
   254	    }
   255	
   256	    if character != '\\' {
   257	        return (chars.get(start + 2) == Some(&'\'')).then_some(start + 3);
   258	    }
   259	
   260	    let escaped = *chars.get(start + 2)?;
   261	    let mut cursor = start + 3;
   262	    if escaped == 'u' && chars.get(cursor) == Some(&'{') {
   263	        cursor += 1;
   264	        while cursor < chars.len() && chars[cursor] != '}' {
   265	            if chars[cursor] == '\n' {
   266	                return None;
   267	            }
   268	            cursor += 1;
   269	        }
   270	        if chars.get(cursor) != Some(&'}') {
   271	            return None;
   272	        }
   273	        cursor += 1;
   274	    } else if escaped == 'x' {
   275	        cursor += 2;
   276	    }
   277	
   278	    (chars.get(cursor) == Some(&'\'')).then_some(cursor + 1)
   279	}
