   281	fn has_forbidden_outer_layer_import(compact_statement: &str, layer: &str) -> bool {
   282	    if import_from_root_references_layer(compact_statement, "crate", layer) {
   283	        return true;
   284	    }
   285	
   286	    for depth in 1..=4 {
   287	        if import_from_root_references_layer(compact_statement, &relative_root(depth), layer) {
   288	            return true;
   289	        }
   290	    }
   291	
   292	    false
   293	}
