   295	fn import_from_root_references_layer(compact_statement: &str, root: &str, layer: &str) -> bool {
   296	    let prefix = format!("use{root}::");
   297	    let Some(import_path) = compact_statement.strip_prefix(&prefix) else {
   298	        return false;
   299	    };
   300	
   301	    starts_with_layer_segment(import_path, layer)
   302	        || import_path
   303	            .strip_prefix('{')
   304	            .is_some_and(|group| grouped_import_references_layer(group, layer))
   305	}
   306	
   307	fn grouped_import_references_layer(group: &str, layer: &str) -> bool {
   308	    starts_with_layer_segment(group, layer)
   309	        || group.match_indices(',').any(|(index, _)| {
   310	            let next_segment = &group[index + 1..];
   311	            starts_with_layer_segment(next_segment, layer)
   312	        })
   313	}
   314	
   315	fn starts_with_layer_segment(import_path: &str, layer: &str) -> bool {
   316	    let Some(remainder) = import_path.strip_prefix(layer) else {
   317	        return false;
   318	    };
   319	
   320	    remainder.starts_with("::")
   321	        || remainder.starts_with(';')
   322	        || remainder.starts_with(',')
   323	        || remainder.starts_with('}')
   324	        || remainder.starts_with("as")
   325	}
