   327	fn direct_outer_layer_reference_patterns(layer: &str) -> Vec<String> {
   328	    let mut patterns = vec![format!("crate::{layer}::")];
   329	
   330	    for depth in 1..=4 {
   331	        patterns.push(format!("{}::{layer}::", relative_root(depth)));
   332	    }
   333	
   334	    patterns
   335	}
