    41	pub fn connect_postgres_test_store(
    42	    target: &TestDatabaseTarget,
    43	    reset_schema: bool,
    44	) -> anyhow::Result<MetadataStore> {
    45	    let runtime = DbRuntime::new()?;
    46	    let database_url = target.database_url.clone();
    47	    let schema_name = target.schema_name.clone();
    48	    let db = run_db_on(&runtime, async move {
    49	        let admin = Database::connect(&database_url).await?;
    50	        admin
    51	            .execute(Statement::from_string(
    52	                admin.get_database_backend(),
    53	                format!(
    54	                    "CREATE SCHEMA IF NOT EXISTS {}",
    55	                    quote_pg_ident(&schema_name)
    56	                ),
    57	            ))
    58	            .await?;
    59	
    60	        let mut options = ConnectOptions::new(database_url);
    61	        options.max_connections(1).min_connections(1);
    62	        let db = Database::connect(options).await?;
    63	        db.execute(Statement::from_string(
    64	            db.get_database_backend(),
    65	            format!("SET search_path TO {}", quote_pg_ident(&schema_name)),
    66	        ))
    67	        .await?;
    68	        if reset_schema {
    69	            schema::reset_metadata_schema(&db).await?;
    70	        }
    71	        schema::migrate_metadata_schema(&db).await?;
    72	        ensure_metadata_lock_row(&db).await?;
    73	        Ok::<_, sea_orm::DbErr>(db)
    74	    })?;
