    76	    Ok(MetadataStore {
    77	        inner: Arc::new(MetadataStoreInner::Postgres {
    78	            db: Arc::new(db),
    79	            runtime,
    80	        }),
    81	        postgres_database_url: Some(Arc::from(target.database_url.clone())),
    82	    })
