   137	fn validate_test_database_url(database_url: &str) -> anyhow::Result<()> {
   138	    let lower = database_url.trim().to_ascii_lowercase();
   139	    if !(lower.starts_with("postgres://") || lower.starts_with("postgresql://")) {
   140	        anyhow::bail!("SCOPE_TEST_DATABASE_URL must be a postgres:// or postgresql:// URL");
   141	    }
   142	
   143	    let after_scheme = lower
   144	        .split_once("://")
   145	        .map(|(_, rest)| rest)
   146	        .unwrap_or_default();
   147	    let database_and_query = after_scheme
   148	        .split_once('/')
   149	        .map(|(_, path)| path)
   150	        .unwrap_or_default();
   151	    let database_name = database_and_query
   152	        .split(['?', '#'])
   153	        .next()
   154	        .unwrap_or_default();
   155	    let query = database_and_query
   156	        .split_once('?')
   157	        .map(|(_, query)| query.split('#').next().unwrap_or_default())
   158	        .unwrap_or_default();
   159	    let query_has_schema_marker = query
   160	        .split('&')
   161	        .filter_map(|part| part.split_once('='))
   162	        .any(|(key, value)| {
   163	            matches!(
   164	                key,
   165	                "search_path" | "schema" | "current_schema" | "currentschema"
   166	            ) && has_scope_test_marker(value)
   167	        });
   168	    let has_test_marker = has_scope_test_marker(database_name) || query_has_schema_marker;
   169	
   170	    if !has_test_marker {
   171	        anyhow::bail!(
   172	            "SCOPE_TEST_DATABASE_URL must visibly target a Scope test database or schema; include scope_test, scope-test, scope_vcs_test, or scope-vcs-test in the database name or search_path/schema query"
   173	        );
   174	    }
   175	    Ok(())
   176	}
   177	
   178	fn has_scope_test_marker(value: &str) -> bool {
   179	    value.contains("scope_test")
   180	        || value.contains("scope-test")
   181	        || value.contains("scope_vcs_test")
   182	        || value.contains("scope-vcs-test")
   183	}
   184	
   185	fn unique_test_schema_name() -> String {
   186	    let nanos = std::time::SystemTime::now()
   187	        .duration_since(std::time::UNIX_EPOCH)
   188	        .expect("system clock should be after UNIX epoch")
   189	        .as_nanos();
   190	    format!("scope_test_{}_{}", std::process::id(), nanos)
   191	}
   192	
   193	fn quote_pg_ident(identifier: &str) -> String {
   194	    assert!(
   195	        identifier
   196	            .bytes()
   197	            .all(|byte| byte.is_ascii_alphanumeric() || byte == b'_'),
   198	        "generated test schema identifiers only use postgres-safe characters"
   199	    );
   200	    format!("\"{}\"", identifier.replace('"', "\"\""))
   201	}
